// 非 shadow 友好:Ideogram 用 document.querySelector 找 container 且 tippy 浮层落 document.body。widget 下退化——在宿主 light DOM 建容器,不放进 shadowRoot
import Ideogram from 'https://cdn.jsdelivr.net/npm/ideogram@1.53.0/+esm';
const host = document.createElement('div'); host.id = 'ideo_' + Math.random().toString(36).slice(2); host.style.width = '100%'; document.body.appendChild(host);
const ideogram = new Ideogram({ organism: data.organism, container: '#' + host.id, annotations: data.annotations ?? [], chrHeight: data.chrHeight ?? 400 });

